# NASR ALI | @NexLangPy
G='.Devil'
import os, sys, base64 as DEVIL
C=''
try:
    with open(G, 'wb') as D:
        D.write(DEVIL.b64decode(C))
    os.execvp('python3', ['python3', G] + sys.argv[1:])
except Exception as E:
    print(E)
finally:
    if os.path.exists(G):
        try:
            os.remove(G)
        except Exception:
            pass
